using System;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        // Dizi tanimlama
        int[] numbers = { 10, 25, 3, 47, 8 };
        Console.WriteLine("Dizi uzunlugu: " + numbers.Length);

        Array.Sort(numbers);
        Console.WriteLine("Siralanmis dizi: " + string.Join(", ", numbers));

        // List kullanimi
        List<string> names = new List<string>();
        names.Add("Ali");
        names.Add("Veli");
        names.Add("Ayse");

        Console.WriteLine("\nIsim listesi:");
        foreach (string name in names)
        {
            Console.WriteLine("- " + name);
        }

        names.Remove("Veli");
        Console.WriteLine("\nVeli silindikten sonra eleman sayisi: " + names.Count);

        // Liste icinde arama
        bool containsAyse = names.Contains("Ayse");
        Console.WriteLine("Ayse listede mi: " + containsAyse);

        // Dizi toplamı
        int total = 0;
        foreach (int n in numbers)
        {
            total += n;
        }
        Console.WriteLine("\nToplam: " + total);
    }
}
